diff --git a/src/auth/session.rs b/src/auth/session.rs
--- a/src/auth/session.rs
+++ b/src/auth/session.rs
@@ -18,7 +18,7 @@ impl SessionStore {
     pub fn validate_token(&self, token: &str) -> bool {
-        self.tokens.contains(token)
+        self.tokens.contains(token) && !self.revoked.contains(token)
     }

     pub fn revoke(&self, token: &str) {
         self.revoked.insert(token.to_string());
     }
